        // 逐个应用替换（按原文长度从长到短排序，避免重叠问题）
        jsonRefine.sort((a, b) => b.original.length - a.original.length);

        let replaceCount = 0;
        for (let i = 0; i < jsonRefine.length; i++) {
          const refine = jsonRefine[i];
          chat_mes = chat_mes.replaceAll(refine.original, refine.corrected);
